#[test]
fn blend_fee_target_matches_fixture() {
    let fx = rails_fixture("blend_target");
    for case in fx["cases"].as_array().unwrap() {
        let current = case["current_fee_ppm"].as_i64().unwrap();
        let bounded_target = case["bounded_target_ppm"].as_i64().unwrap();
        let woke = case["woke_from_sleep"].as_bool().unwrap();
        let sparse = case["sparse_data_conservative"].as_bool().unwrap();
        let std = parse_f(&case["posterior_std"]);
        let profile_name = case["profile_name"].as_str().unwrap();
        let (_, profile) = fee_profile(profile_name);

        let (blended, diag) = blend_fee_target(
            current,
            bounded_target,
            woke,
            sparse,
            std,
            profile_name,
            profile,
        );

        assert_eq!(
            blended,
            case["expected_blended_target_ppm"].as_i64().unwrap(),
            "case {case}"
        );
        let expected_diag = &case["expected_diag"];
        assert_eq!(
            py_repr(diag.blend_ratio),
            expected_diag["blend_ratio"].as_str().unwrap()
        );
        assert_eq!(
            diag.blended_delta_ppm,
            expected_diag["blended_delta_ppm"].as_i64().unwrap()
        );
        assert_eq!(
            diag.sparse_data_conservative,
            expected_diag["sparse_data_conservative"].as_bool().unwrap()
        );
    }
}

