#[test]
fn zero_flow_ratchet_guard_matches_fixture() {
    let fx = rails_fixture("zero_flow_guard");
    for case in fx["cases"].as_array().unwrap() {
        let label = case["label"].as_str().unwrap();
        let inputs = &case["inputs"];
        let zfi = ZeroFlowInputs {
            current_fee: inputs["current_fee"].as_i64().unwrap(),
            target_fee: inputs["target_fee"].as_i64().unwrap(),
            min_fee: inputs["min_fee"].as_i64().unwrap(),
            zero_revenue_streak: inputs["zero_revenue_streak"].as_i64().unwrap(),
            forwards_since_update: inputs["forwards_since_update"].as_i64().unwrap(),
            revenue_rate: parse_f(&inputs["revenue_rate"]),
            supported_fee_ceiling: parse_opt_f(&inputs["supported_fee_ceiling"]),
            earning_anchor_ppm: parse_opt_f(&inputs["earning_anchor_ppm"]),
            guard_streak: inputs["guard_streak"].as_i64(),
            downshift_streak: inputs["downshift_streak"].as_i64(),
            rate_is_meaningful: inputs["rate_is_meaningful"].as_bool(),
        };

        let (fee, tag) = apply_zero_flow_ratchet_guard(&zfi);
        assert_eq!(fee, case["expected_fee"].as_i64().unwrap(), "{label}: fee");
        let expected_tag = case["expected_tag"].as_str();
        assert_eq!(tag, expected_tag, "{label}: tag");
    }
}

